func (c *Connector) QueryMeter(ctx context.Context, namespace string, meter meterpkg.Meter, params streaming.QueryParams) ([]meterpkg.MeterQueryRow, error) {
	if namespace == "" {
		return nil, fmt.Errorf("namespace is required")
	}
	if err := params.Validate(); err != nil {
		return nil, fmt.Errorf("validate params: %w", err)
	}
	query := queryMeter{Database: c.config.Database, EventsTableName: c.config.EventsTableName, Namespace: namespace, Meter: meter /* ... */}
	sql, args, err := query.toSQL()
	if err != nil {
		return nil, fmt.Errorf("build sql query: %w", err)
	}
	rows, err := c.config.ClickHouse.Query(ctx, sql, args...)
	if err != nil {
		if strings.Contains(err.Error(), "code: 60") {
			return nil, meterpkg.NewMeterNotFoundError(query.Meter.Key)
		}
		return nil, fmt.Errorf("clickhouse query: %w", err)
	}
	defer rows.Close()
	return query.scanRows(rows)
}

func withRetry[T any](ctx context.Context, c *Connector, fn func() (T, error)) (T, error) {
	return retry.DoWithData(fn,
		retry.Context(ctx),
		retry.Attempts(uint(c.maxTries)),
		retry.LastErrorOnly(true),
		retry.DelayType(retry.CombineDelay(retry.BackOffDelay, retry.RandomDelay)),
		retry.Delay(c.retryWaitDuration),
		retry.MaxDelay(c.maxDelay),
		retry.RetryIf(func(err error) bool {
			if errors.Is(err, io.ErrUnexpectedEOF) || errors.Is(err, io.EOF) {
				return true
			}
			if errors.Is(err, clickhouse.ErrAcquireConnTimeout) {
				return true
			}
